export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    if (url.pathname === '/sw.js') {
      return new Response(atob(''), { headers: { 'Content-Type': 'application/javascript', 'Cache-Control': 'no-cache' } });
    }
    if (url.pathname === '/manifest.json') {
      return new Response(atob(''), { headers: { 'Content-Type': 'application/manifest+json', 'Cache-Control': 'no-cache' } });
    }
    const html = atob('');
    return new Response(html, { headers: { 'Content-Type': 'text/html', 'Cache-Control': 'no-cache, no-store, must-revalidate' } });
  }
};
